using UnityEngine;using System;
public class ComboSystem : MonoBehaviour{public static ComboSystem Instance{get;private set;}public int CurrentCombo{get;private set;}public int CurrentMultiplier{get;private set;}=1;[SerializeField]private float comboWindow=1.5f;public Action<int,int> OnComboUpdated;private float timer;private void Awake(){if(Instance==null)Instance=this;else{Destroy(gameObject);return;}}private void OnEnable(){if(GameManager.Instance!=null)GameManager.Instance.OnGameStart+=Reset;}private void OnDisable(){if(GameManager.Instance!=null)GameManager.Instance.OnGameStart-=Reset;}private void Update(){if(CurrentCombo>0){timer-=Time.deltaTime;if(timer<=0){Reset();}}}
public void RegisterMerge(){CurrentCombo++;timer=comboWindow;CurrentMultiplier=CurrentCombo>=10?25:(CurrentCombo>=8?10:(CurrentCombo>=5?5:(CurrentCombo>=3?2:1)));OnComboUpdated?.Invoke(CurrentCombo,CurrentMultiplier);if(CurrentCombo>=3)CameraShake.Instance?.Shake(0.03f*CurrentMultiplier,0.1f);}private void Reset(){CurrentCombo=0;CurrentMultiplier=1;timer=0;OnComboUpdated?.Invoke(0,1);}}